func (o *SeasonDriver) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "CarModel":
		rel, ok := retrieved.(*CarModel)
		if !ok {
			return fmt.Errorf("seasonDriver cannot load %T as %q", retrieved, name)
		}

		o.R.CarModel = rel
		o.R.Loaded.CarModel = true

		if rel != nil {
			rel.R.SeasonDrivers = SeasonDriverSlice{o}
		}
		return nil
	case "Driver":
		rel, ok := retrieved.(*Driver)
		if !ok {
			return fmt.Errorf("seasonDriver cannot load %T as %q", retrieved, name)
		}

		o.R.Driver = rel
		o.R.Loaded.Driver = true

		if rel != nil {
			rel.R.SeasonDrivers = SeasonDriverSlice{o}
		}
		return nil
	case "Season":
		rel, ok := retrieved.(*Season)
		if !ok {
			return fmt.Errorf("seasonDriver cannot load %T as %q", retrieved, name)
		}

		o.R.Season = rel
		o.R.Loaded.Season = true

		if rel != nil {
			rel.R.SeasonDrivers = SeasonDriverSlice{o}
		}
		return nil
	default:
		return fmt.Errorf("seasonDriver has no relationship %q", name)
	}
}

