// LoadCarModel loads the seasonDriver's CarModel into the .R struct
func (o *SeasonDriver) LoadCarModel(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.CarModel = nil
	o.R.Loaded.CarModel = false

	related, err := o.CarModel(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.SeasonDrivers = SeasonDriverSlice{o}

	o.R.CarModel = related
	o.R.Loaded.CarModel = true
	return nil
}

// LoadCarModel loads the seasonDriver's CarModel into the .R struct
func (os SeasonDriverSlice) LoadCarModel(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	carModels, err := os.CarModel(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.CarModel = nil
		o.R.Loaded.CarModel = true
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range carModels {

			if !(o.CarModelID == rel.ID) {
				continue
			}

			rel.R.SeasonDrivers = append(rel.R.SeasonDrivers, o)

			o.R.CarModel = rel
			break
		}
	}

	return nil
}

