type seasonDriverJoins[Q dialect.Joinable] struct {
	typ      string
	CarModel modAs[Q, carModelColumns]
	Driver   modAs[Q, driverColumns]
	Season   modAs[Q, seasonColumns]
}

func (j seasonDriverJoins[Q]) aliasedAs(alias string) seasonDriverJoins[Q] {
	return buildSeasonDriverJoins[Q](buildSeasonDriverColumns(alias), j.typ)
}

func buildSeasonDriverJoins[Q dialect.Joinable](cols seasonDriverColumns, typ string) seasonDriverJoins[Q] {
	return seasonDriverJoins[Q]{
		typ: typ,
		CarModel: modAs[Q, carModelColumns]{
			c: CarModels.Columns,
			f: func(to carModelColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, CarModels.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.CarModelID),
					))
				}

				return mods
			},
		},
		Driver: modAs[Q, driverColumns]{
			c: Drivers.Columns,
			f: func(to driverColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Drivers.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.DriverID),
					))
				}

				return mods
			},
		},
		Season: modAs[Q, seasonColumns]{
			c: Seasons.Columns,
			f: func(to seasonColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Seasons.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.SeasonID),
					))
				}

				return mods
			},
		},
	}
}
